  1→/**
  2→ * 2263-复制镜像功能优化 - 接口测试脚本
  3→ * 分支: feature/batch-copy-2263
  4→ *
  5→ * 用法: node test-api.js
  6→ * 要求: Node.js 18+（原生 fetch）
  7→ *
  8→ * 覆盖接口:
  9→ *   GET  /spaceNode/migration/managedSpaces      — 返回空间站列表（含文件夹树）
 10→ *   POST /spaceNode/migration/createMigrationTask — 创建迁移任务（含 targetParentNodeId）
 11→ */
 12→
 13→// ========== 配置 ==========
 14→const CONFIG = {
 15→  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
 16→  adminEmail: 'test@yottastudios.com',
 17→  normalEmail: 'test2@yottastudios.com',
 18→  spaceId: 'spcQB8z3iXMF0',  // nanbei 空间站
 19→  // 运行时动态获取
 20→  folderNodeId: null,   // type=1 的文件夹节点
 21→  fileNodeId: null,     // type=2 的文件节点
 22→  targetSpaceId: null,  // 目标空间站（从 managedSpaces 动态取）
 23→  targetFolderId: null, // 目标文件夹 ID
 24→};
 25→
 26→// ========== 测试框架 ==========
 27→let passed = 0;
 28→let failed = 0;
 29→let cookie = '';
 30→
 31→function assert(name, condition, detail) {
 32→  if (condition) {
 33→    console.log(`  ✅ ${name}`);
 34→    passed++;
 35→  } else {
 36→    console.log(`  ❌ ${name}`);
 37→    if (detail !== undefined)
 38→      console.log(`     实际值:`, typeof detail === 'object'
 39→        ? JSON.stringify(detail).slice(0, 300) : detail);
 40→    failed++;
 41→  }
 42→}
 43→
 44→// ========== HTTP 工具 ==========
 45→
 46→function parseCookies(res) {
 47→  const cookies = {};
 48→  const setCookieHeaders = res.headers.getSetCookie?.() || [];
 49→  for (const header of setCookieHeaders) {
 50→    const [kv] = header.split(';');
 51→    const eqIdx = kv.indexOf('=');
 52→    if (eqIdx > 0) {
 53→      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
 54→    }
 55→  }
 56→  return cookies;
 57→}
 58→
 59→async function rawFetch(method, url, body, spaceIdOverride) {
 60→  const headers = {
 61→    'content-type': 'application/json',
 62→  };
 63→  const sid = spaceIdOverride || CONFIG.spaceId;
 64→  if (sid) headers['x-space-id'] = sid;
 65→  if (cookie) headers['cookie'] = cookie;
 66→
 67→  const opts = { method, headers, redirect: 'manual' };
 68→  if (body) opts.body = JSON.stringify(body);
 69→  return fetch(url, opts);
 70→}
 71→
 72→async function GET(path) {
 73→  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
 74→  const text = await res.text();
 75→  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
 76→}
 77→
 78→async function POST(path, body) {
 79→  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
 80→  const text = await res.text();
 81→  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
 82→}
 83→
 84→// ========== 登录管理 ==========
 85→
 86→async function login() {
 87→  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
 88→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
 89→    { redirect: 'manual' });
 90→  const cookies = parseCookies(res);
 91→  const allCookies = Object.entries(cookies);
 92→  if (allCookies.length > 0) {
 93→    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
 94→    console.log(`   ✅ 登录成功\n`);
 95→    return;
 96→  }
 97→  console.log('❌ 登录失败');
 98→  process.exit(1);
 99→}
100→
101→let savedSessions = {};
102→function saveSession(name) {
103→  savedSessions[name] = { cookie };
104→}
105→function restoreSession(name) {
106→  ({ cookie } = savedSessions[name]);
107→}
108→
109→async function loginAs(email) {
110→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
111→    { redirect: 'manual' });
112→  const cookies = parseCookies(res);
113→  const allCookies = Object.entries(cookies);
114→  if (allCookies.length > 0) {
115→    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
116→    return true;
117→  }
118→  console.log(`  ⚠️  登录 ${email} 失败，跳过`);
119→  return false;
120→}
121→
122→// ========== 工具函数 ==========
123→
124→/** 递归收集文件夹树中所有节点 */
125→function flattenFolders(folders) {
126→  const result = [];
127→  for (const f of (folders || [])) {
128→    result.push(f);
129→    result.push(...flattenFolders(f.children));
130→  }
131→  return result;
132→}
133→
134→// ========== 测试用例 ==========
135→
136→// ---------- §1. managedSpaces 返回文件夹树 ----------
137→
138→async function test_S1_managedSpaces_basic() {
139→  console.log('\n📋 §1. GET /managedSpaces - 正常流程');
140→
141→  const res = await GET('/spaceNode/migration/managedSpaces');
142→  assert('§1 接口返回 success', res.success === true, res);
143→  assert('§1 data 是数组', Array.isArray(res.data), res.data);
144→  assert('§1 至少返回 1 个空间站', res.data?.length > 0, res.data?.length);
145→
146→  if (res.data?.length > 0) {
147→    const first = res.data[0];
148→    assert('§1 空间站含 spaceId (string)', typeof first.spaceId === 'string', first.spaceId);
149→    assert('§1 空间站含 name (string)', typeof first.name === 'string', first.name);
150→    const foldersDeployed = first.folders !== undefined;
151→    assert('§1 空间站含 folders 字段（需部署后生效）', foldersDeployed, first);
152→    if (foldersDeployed) {
153→      assert('§1 folders 是数组', Array.isArray(first.folders), first.folders);
154→    }
155→
156→    // 找一个有 folders 的空间站
157→    const withFolders = foldersDeployed ? res.data.find(s => s.folders && s.folders.length > 0) : null;
158→    if (withFolders) {
159→      const folder = withFolders.folders[0];
160→      assert('§1 folder 含 id', folder.id != null, folder);
161→      assert('§1 folder 含 name (string)', typeof folder.name === 'string', folder.name);
162→      assert('§1 folder 含 children (数组)', Array.isArray(folder.children), folder.children);
163→
164→      // 保存测试数据
165→      CONFIG.targetSpaceId = withFolders.spaceId;
166→      CONFIG.targetFolderId = folder.id;
167→      console.log(`   ℹ️  目标空间站: ${withFolders.spaceId} (${withFolders.name}), 目标文件夹ID: ${folder.id} (${folder.name})`);
168→    } else {
169→      // 没有文件夹的空间站也行，设置 targetSpaceId
170→      CONFIG.targetSpaceId = first.spaceId;
171→      console.log(`   ℹ️  目标空间站: ${first.spaceId} (${first.name})，无文件夹`);
172→    }
173→  }
174→}
