/**
 * 2263-复制镜像功能优化 - 接口测试脚本
 * 分支: feature/batch-copy-2263
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 *
 * 覆盖接口:
 *   GET  /spaceNode/migration/managedSpaces      — 返回空间站列表（含文件夹树）
 *   POST /spaceNode/migration/createMigrationTask — 创建迁移任务（含 targetParentNodeId）
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  adminEmail: 'test@yottastudios.com',
  normalEmail: 'test2@yottastudios.com',
  spaceId: 'spcQB8z3iXMF0',  // nanbei 空间站
  // 运行时动态获取
  folderNodeId: null,   // type=1 的文件夹节点
  fileNodeId: null,     // type=2 的文件节点
  targetSpaceId: null,  // 目标空间站（从 managedSpaces 动态取）
  targetFolderId: null, // 目标文件夹 ID
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const eqIdx = kv.indexOf('=');
    if (eqIdx > 0) {
      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
    }
  }
  return cookies;
}

async function rawFetch(method, url, body, spaceIdOverride) {
  const headers = {
    'content-type': 'application/json',
  };
  const sid = spaceIdOverride || CONFIG.spaceId;
  if (sid) headers['x-space-id'] = sid;
  if (cookie) headers['cookie'] = cookie;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  const text = await res.text();
  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  const text = await res.text();
  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
}

// ========== 登录管理 ==========

async function login() {
  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  const allCookies = Object.entries(cookies);
  if (allCookies.length > 0) {
    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
    console.log(`   ✅ 登录成功\n`);
    return;
  }
  console.log('❌ 登录失败');
  process.exit(1);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie };
}
function restoreSession(name) {
  ({ cookie } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  const allCookies = Object.entries(cookies);
  if (allCookies.length > 0) {
    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
    return true;
  }
  console.log(`  ⚠️  登录 ${email} 失败，跳过`);
  return false;
}

// ========== 工具函数 ==========

/** 递归收集文件夹树中所有节点 */
function flattenFolders(folders) {
  const result = [];
  for (const f of (folders || [])) {
    result.push(f);
    result.push(...flattenFolders(f.children));
  }
  return result;
}

// ========== 测试用例 ==========

// ---------- §1. managedSpaces 返回文件夹树 ----------

async function test_S1_managedSpaces_basic() {
  console.log('\n📋 §1. GET /managedSpaces - 正常流程');

  const res = await GET('/spaceNode/migration/managedSpaces');
  assert('§1 接口返回 success', res.success === true, res);
  assert('§1 data 是数组', Array.isArray(res.data), res.data);
  assert('§1 至少返回 1 个空间站', res.data?.length > 0, res.data?.length);

  if (res.data?.length > 0) {
    const first = res.data[0];
    assert('§1 空间站含 spaceId (string)', typeof first.spaceId === 'string', first.spaceId);
    assert('§1 空间站含 name (string)', typeof first.name === 'string', first.name);
    const foldersDeployed = first.folders !== undefined;
    assert('§1 空间站含 folders 字段（需部署后生效）', foldersDeployed, first);
    if (foldersDeployed) {
      assert('§1 folders 是数组', Array.isArray(first.folders), first.folders);
    }

    // 找一个有 folders 的空间站
    const withFolders = foldersDeployed ? res.data.find(s => s.folders && s.folders.length > 0) : null;
    if (withFolders) {
      const folder = withFolders.folders[0];
      assert('§1 folder 含 id', folder.id != null, folder);
      assert('§1 folder 含 name (string)', typeof folder.name === 'string', folder.name);
      assert('§1 folder 含 children (数组)', Array.isArray(folder.children), folder.children);

      // 保存测试数据
      CONFIG.targetSpaceId = withFolders.spaceId;
      CONFIG.targetFolderId = folder.id;
      console.log(`   ℹ️  目标空间站: ${withFolders.spaceId} (${withFolders.name}), 目标文件夹ID: ${folder.id} (${folder.name})`);
    } else {
      // 没有文件夹的空间站也行，设置 targetSpaceId
      CONFIG.targetSpaceId = first.spaceId;
      console.log(`   ℹ️  目标空间站: ${first.spaceId} (${first.name})，无文件夹`);
    }
  }
}

async function test_S1_managedSpaces_folderStructure() {
  console.log('\n📋 §1. managedSpaces - folders 结构深度验证');

  const res = await GET('/spaceNode/migration/managedSpaces');
  if (!res.success || !res.data) return;

  // 检查第一个空间站是否有 folders 字段（判断功能是否已部署）
  const first = res.data[0];
  if (first.folders === undefined) {
    console.log('   ⚠️  folders 字段不存在，功能分支尚未部署到测试环境，跳过 folders 深度验证');
    assert('§1 [待部署] folders 字段存在', false, 'undefined - 需要部署后重测');
    return;
  }

  // 抽查前 3 个空间站的 folders 是数组
  const sample = res.data.slice(0, 3);
  for (const space of sample) {
    assert(`§1 ${space.name} folders 非null`, space.folders != null, space.folders);
    assert(`§1 ${space.name} folders 是数组`, Array.isArray(space.folders), typeof space.folders);
  }

  // 找有嵌套文件夹的空间站验证递归结构
  const withFolders = res.data.find(s => s.folders && s.folders.length > 0);
  if (withFolders) {
    const allFolders = flattenFolders(withFolders.folders);
    console.log(`   ℹ️  ${withFolders.name} 共 ${allFolders.length} 个文件夹节点`);
    // 验证前 5 个节点的结构（避免大量输出）
    for (const f of allFolders.slice(0, 5)) {
      assert(`§1 文件夹 ${String(f.id)} 含 name`, typeof f.name === 'string', f);
      assert(`§1 文件夹 ${String(f.id)} children 是数组`, Array.isArray(f.children), f.children);
    }
  } else {
    console.log('   ℹ️  所有空间站均无文件夹，跳过递归结构验证');
  }
}

async function test_S1_managedSpaces_appsCompat() {
  console.log('\n📋 §1. managedSpaces - 原有字段兼容性');

  const res = await GET('/spaceNode/migration/managedSpaces');
  if (!res.success || !res.data?.length) return;

  const first = res.data[0];
  // 原有字段不能丢失
  assert('§1 兼容 spaceId', typeof first.spaceId === 'string', first.spaceId);
  assert('§1 兼容 name', typeof first.name === 'string', first.name);
  assert('§1 兼容 owner', first.owner != null, first.owner);
  assert('§1 兼容 apps 字段', Array.isArray(first.apps), first.apps);
}

// ---------- §2. createMigrationTask 支持 targetParentNodeId ----------

async function test_S2_createTask_paramValidation() {
  console.log('\n📋 §2. POST /createMigrationTask - 参数校验');

  // 缺少必填字段 spaceNodeIds
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    targetSpaceId: CONFIG.targetSpaceId,
  });
  assert('§2 缺少 spaceNodeIds 返回错误', r1.success === false, r1);
  assert('§2 缺少 spaceNodeIds 非500', r1.code !== 500, r1.code);

  // 空 spaceNodeIds 列表
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [],
    targetSpaceId: CONFIG.targetSpaceId,
  });
  assert('§2 空 spaceNodeIds 返回错误', r2.success === false, r2);
  assert('§2 空 spaceNodeIds 非500', r2.code !== 500, r2.code);

  // 缺少 targetSpaceId
  const r3 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
  });
  assert('§2 缺少 targetSpaceId 返回错误', r3.success === false, r3);
  assert('§2 缺少 targetSpaceId 非500', r3.code !== 500, r3.code);

  // 空 body
  const r4 = await POST('/spaceNode/migration/createMigrationTask', {});
  assert('§2 空 body 返回错误', r4.success === false, r4);
  assert('§2 空 body 非500', r4.code !== 500, r4.code);
}

async function test_S2_createTask_notExist() {
  console.log('\n📋 §2. createMigrationTask - 不存在的数据');

  // 不存在的 spaceNodeId（合法 Long）
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: CONFIG.targetSpaceId,
  });
  assert('§2 不存在 spaceNodeId 不报500', r1.code !== 500, r1);

  // 不存在的 targetSpaceId
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: 'spcNotExist000',
  });
  assert('§2 不存在 targetSpaceId 不报500', r2.code !== 500, r2);

  // 不存在的 targetParentNodeId（合法 Long）
  const r3 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: CONFIG.targetSpaceId,
    targetParentNodeId: 1,
  });
  assert('§2 不存在 targetParentNodeId 不报500', r3.code !== 500, r3);
}

async function test_S2_createTask_optionalTarget() {
  console.log('\n📋 §2. createMigrationTask - targetParentNodeId 可选性');

  // 不传 targetParentNodeId（向后兼容，放根目录）
  // 注意：这会真正创建任务，用不存在的节点ID避免实际迁移数据
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: CONFIG.targetSpaceId || 'spcQB8z3iXMF0',
  });
  // 不传 targetParentNodeId 不应该报参数校验错误（它是可选的）
  // 可能因为 spaceNodeId=1 不存在而业务失败，但不应是参数校验失败
  assert('§2 不传 targetParentNodeId 不报参数校验错误',
    r1.code !== 400 || r1.success === true, r1);
  assert('§2 不传 targetParentNodeId 不报500', r1.code !== 500, r1.code);

  // 传 null
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: CONFIG.targetSpaceId || 'spcQB8z3iXMF0',
    targetParentNodeId: null,
  });
  assert('§2 targetParentNodeId=null 不报500', r2.code !== 500, r2.code);
}

async function test_S2_createTask_injection() {
  console.log('\n📋 §2. createMigrationTask - 注入防护');

  // targetSpaceId 注入
  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE xxx;",
    "<script>alert(1)</script>",
  ];
  for (const payload of injections) {
    const r = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [1],
      targetSpaceId: payload,
    });
    assert(`§2 targetSpaceId注入 "${payload.slice(0, 20)}" 非500`, r.code !== 500, r.code);
  }
}

// ---------- §3. 批量选择文件和文件夹 ----------

async function test_S3_createTask_batchSelect() {
  console.log('\n📋 §3. createMigrationTask - 批量选择（多个 spaceNodeIds）');

  // 多个节点ID（包括文件和文件夹）
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1, 2, 3],
    targetSpaceId: CONFIG.targetSpaceId || 'spcQB8z3iXMF0',
  });
  // 不存在的 ID 可能导致业务错误，但格式应正确，不应500
  assert('§3 多个 spaceNodeIds 不报500', r1.code !== 500, r1.code);

  // 单个节点
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: CONFIG.targetSpaceId || 'spcQB8z3iXMF0',
  });
  assert('§3 单个 spaceNodeId 不报500', r2.code !== 500, r2.code);
}

// ---------- 维度 5：特殊字符 ----------

async function test_D5_specialChars() {
  console.log('\n🛡️ 维度5: managedSpaces 特殊字符（x-space-id header）');

  // 伪造 x-space-id
  const fakeSpaceIds = ['', ' ', "' OR 1=1", '<script>', 'spcNotExist'];
  for (const fakeId of fakeSpaceIds) {
    const res = await rawFetch('GET', `${CONFIG.host}/api/v1/spaceNode/migration/managedSpaces`, null, fakeId);
    const text = await res.text();
    let json;
    try { json = JSON.parse(text); } catch { json = { _raw: text, _status: res.status }; }
    assert(`维度5 x-space-id="${fakeId.slice(0, 15)}" 非500`,
      json.code !== 500 && res.status !== 500, json);
  }
}

// ---------- 维度 7：多账号权限 ----------

async function test_D7_managedSpaces_multiAccount() {
  console.log('\n👤👤 维度7: managedSpaces - 多账号');
  saveSession('admin');

  // 管理员能调用
  const adminRes = await GET('/spaceNode/migration/managedSpaces');
  assert('维度7 管理员可调用 managedSpaces', adminRes.success === true, adminRes);

  // 普通用户也能调用（requiredPermission = false）
  if (await loginAs(CONFIG.normalEmail)) {
    const normalRes = await GET('/spaceNode/migration/managedSpaces');
    assert('维度7 普通用户可调用 managedSpaces', normalRes.success === true, normalRes);
    // 普通用户返回的空间站列表可能不同（只返回自己管理的）
    assert('维度7 普通用户返回数据是数组', Array.isArray(normalRes.data), normalRes.data);

    // 普通用户返回的空间站也应有 folders 字段
    if (normalRes.data?.length > 0) {
      assert('维度7 普通用户空间站也有 folders', normalRes.data[0].folders !== undefined, normalRes.data[0]);
    }
  }

  restoreSession('admin');
}

async function test_D7_createTask_multiAccount() {
  console.log('\n🚫👤 维度7: createMigrationTask - 多账号权限');
  saveSession('admin');

  // createMigrationTask 需要 requiredSpaceAdmin = true
  // 普通用户应被拒绝
  if (await loginAs(CONFIG.normalEmail)) {
    const r = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [1],
      targetSpaceId: CONFIG.targetSpaceId || 'spcQB8z3iXMF0',
    });
    assert('维度7 普通用户 createTask 被拒绝', r.success === false, r);
    assert('维度7 普通用户 createTask 非500', r.code !== 500, r.code);
  }

  restoreSession('admin');
}

async function test_D7_unauthenticated() {
  console.log('\n🔒 维度7: 未登录访问');
  saveSession('admin');
  cookie = '';

  // GET managedSpaces 未登录
  const getRes = await rawFetch('GET', `${CONFIG.host}/api/v1/spaceNode/migration/managedSpaces`);
  assert('维度7 未登录 GET managedSpaces 非500', getRes.status !== 500, getRes.status);

  // POST createMigrationTask 未登录
  const postRes = await rawFetch('POST', `${CONFIG.host}/api/v1/spaceNode/migration/createMigrationTask`,
    { spaceNodeIds: [1], targetSpaceId: 'spcQB8z3iXMF0' });
  assert('维度7 未登录 POST createTask 非200', postRes.status !== 200, postRes.status);

  restoreSession('admin');
}

// ---------- 维度 9：并发 ----------

async function test_D9_concurrency() {
  console.log('\n🔀 维度9: managedSpaces 并发请求');

  const promises = Array.from({ length: 5 }, () =>
    GET('/spaceNode/migration/managedSpaces')
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('维度9 5个并发 managedSpaces 全部成功', allOk);

  // 结果一致性
  if (results.length >= 2) {
    assert('维度9 并发结果 data 长度一致',
      results[0].data?.length === results[1].data?.length);
  }
}

// ---------- 维度 10：响应结构一致性 ----------

async function test_D10_responseStructure() {
  console.log('\n📦 维度10: 响应结构一致性');

  // managedSpaces
  const res = await GET('/spaceNode/migration/managedSpaces');
  assert('维度10 managedSpaces 含 success', typeof res.success === 'boolean', typeof res.success);
  assert('维度10 managedSpaces 含 code', res.code !== undefined, res.code);
  assert('维度10 managedSpaces 含 data', res.data !== undefined);

  // createMigrationTask 的错误响应也应有标准结构
  const errRes = await POST('/spaceNode/migration/createMigrationTask', {});
  assert('维度10 createTask 错误含 success', typeof errRes.success === 'boolean', typeof errRes.success);
  assert('维度10 createTask 错误含 code', errRes.code !== undefined, errRes.code);
  assert('维度10 createTask 错误含 message', errRes.message !== undefined, errRes.message);
}

// ---------- 维度 13：错误码规范 ----------

async function test_D13_errorCodes() {
  console.log('\n🔢 维度13: 错误码规范');

  // 参数校验错误应返回非500
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {});
  assert('维度13 参数校验错误 success=false', r1.success === false);
  assert('维度13 参数校验错误非500', r1.code !== 500, r1.code);

  // 权限不足应返回非500
  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const r2 = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [1],
      targetSpaceId: 'spcQB8z3iXMF0',
    });
    if (r2.success === false) {
      assert('维度13 权限不足非500', r2.code !== 500, r2.code);
    }
  }
  restoreSession('admin');
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 2263-复制镜像功能优化 - 接口测试');
  console.log('');
  console.log('📋 功能点覆盖清单（来自功能点对照文档）：');
  console.log('  §1. managedSpaces 返回文件夹树（GET /managedSpaces 增强）');
  console.log('  §2. createMigrationTask 支持 targetParentNodeId（POST 增强）');
  console.log('  §3. 批量选择文件和文件夹（spaceNodeIds 多选）');
  console.log('');

  try {
    await login();
    saveSession('admin');

    // §1. managedSpaces 返回文件夹树
    await test_S1_managedSpaces_basic();
    await test_S1_managedSpaces_folderStructure();
    await test_S1_managedSpaces_appsCompat();

    // §2. createMigrationTask 支持 targetParentNodeId
    await test_S2_createTask_paramValidation();
    await test_S2_createTask_notExist();
    await test_S2_createTask_optionalTarget();
    await test_S2_createTask_injection();

    // §3. 批量选择
    await test_S3_createTask_batchSelect();

    // 维度补充
    await test_D5_specialChars();
    await test_D7_managedSpaces_multiAccount();
    await test_D7_createTask_multiAccount();
    await test_D7_unauthenticated();
    await test_D9_concurrency();
    await test_D10_responseStructure();
    await test_D13_errorCodes();

  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}
main();

