import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.NotEmpty;
import jakarta.validation.constraints.NotNull;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.util.List;

@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "MigrationTaskCreateRo", description = "迁移任务创建请求对象")
public class MigrationTaskCreateRo {

    @NotEmpty(message = "spaceNodeId列表不能为空")
    @Schema(description = "要复制的spaceNodeId列表", example = "[1, 2, 3]", requiredMode = Schema.RequiredMode.REQUIRED)
    private List<Long> spaceNodeIds;

    @NotNull(message = "目标spaceID不能为空")
    @Schema(description = "目标spaceID", example = "spcVyED5StRev", requiredMode = Schema.RequiredMode.REQUIRED)
    private String targetSpaceId;

    @Schema(description = "是否保留原空间站文件，只有在跨空间站迁移生效，跨网不生效 true保留 false不保留",
            example = "true", requiredMode = Schema.RequiredMode.NOT_REQUIRED)
    private Boolean isRemained;

    @Schema(description = "目标父节点ID（文件夹），复制到该文件夹下；不传则放到空间站根目录",
            example = "123", requiredMode = Schema.RequiredMode.NOT_REQUIRED)
    private Long targetParentNodeId;
}

