@PostResource(path = "/spaceByName", requiredPermission = false, requiredLogin = false)
@Operation(summary = "Get spaceByName for developer")
public ResponseData<List<SpaceEntity>> getSpaceByName(@RequestBody SpaceByName ro) {
    String name = ro.name;
    return ResponseData.success(spaceService.listByName(name));
}
public record SpaceByName(String name) { }

@PostResource(path = "/spaceTreeById", requiredPermission = false)
@Operation(summary = "Get spaceTreeById for developer")
public ResponseData<List<TreeNode<SpaceNodeVo>>> getSpaceTreeById(@RequestBody SpaceId ro) {
    String id = ro.id;
    return ResponseData.success(spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(id));
}
public record SpaceId(String id) { }

@GetResource(path = "/testLogin/{spaceId}/{nodeId}/{userId}", requiredPermission = false)
@Operation(summary = "测试服email登录")
public void testLogin(@PathVariable final String spaceId, @PathVariable String nodeId,@PathVariable Long userId) throws IOException {
    apitableGrpcClientService.deleteNodeTotally(userId,spaceId,nodeId);
}

