  1→/**
  2→ * 2263-复制镜像功能优化 - 接口测试脚本
  3→ * 分支: feature/batch-copy-2263
  4→ *
  5→ * 用法: node test-api.js
  6→ * 要求: Node.js 18+（原生 fetch）
  7→ *
  8→ * 覆盖接口:
  9→ *   GET  /spaceNode/migration/managedSpaces      — 返回空间站列表（含文件夹树）
 10→ *   POST /spaceNode/migration/createMigrationTask — 创建迁移任务（含 targetParentNodeId）
 11→ */
 12→
 13→// ========== 配置 ==========
 14→const CONFIG = {
 15→  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
 16→  adminEmail: 'test@yottastudios.com',
 17→  normalEmail: 'test2@yottastudios.com',
 18→  spaceId: 'spcQB8z3iXMF0',  // nanbei 空间站
 19→  // 运行时动态获取
 20→  folderNodeId: null,   // type=1 的文件夹节点
 21→  fileNodeId: null,     // type=2 的文件节点
 22→  targetSpaceId: null,  // 目标空间站（从 managedSpaces 动态取）
 23→  targetFolderId: null, // 目标文件夹 ID
 24→};
 25→
 26→// ========== 测试框架 ==========
 27→let passed = 0;
 28→let failed = 0;
 29→let cookie = '';
 30→
 31→function assert(name, condition, detail) {
 32→  if (condition) {
 33→    console.log(`  ✅ ${name}`);
 34→    passed++;
 35→  } else {
 36→    console.log(`  ❌ ${name}`);
 37→    if (detail !== undefined)
 38→      console.log(`     实际值:`, typeof detail === 'object'
 39→        ? JSON.stringify(detail).slice(0, 300) : detail);
 40→    failed++;
 41→  }
 42→}
 43→
 44→// ========== HTTP 工具 ==========
 45→
 46→function parseCookies(res) {
 47→  const cookies = {};
 48→  const setCookieHeaders = res.headers.getSetCookie?.() || [];
 49→  for (const header of setCookieHeaders) {
 50→    const [kv] = header.split(';');
 51→    const eqIdx = kv.indexOf('=');
 52→    if (eqIdx > 0) {
 53→      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
 54→    }
 55→  }
 56→  return cookies;
 57→}
 58→
 59→async function rawFetch(method, url, body, spaceIdOverride) {
 60→  const headers = {
 61→    'content-type': 'application/json',
 62→  };
 63→  const sid = spaceIdOverride || CONFIG.spaceId;
 64→  if (sid) headers['x-space-id'] = sid;
 65→  if (cookie) headers['cookie'] = cookie;
 66→
 67→  const opts = { method, headers, redirect: 'manual' };
 68→  if (body) opts.body = JSON.stringify(body);
 69→  return fetch(url, opts);
 70→}
 71→
 72→async function GET(path) {
 73→  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
 74→  const text = await res.text();
 75→  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
 76→}
 77→
 78→async function POST(path, body) {
 79→  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
 80→  const text = await res.text();
 81→  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
 82→}
