 86→async function login() {
 87→  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
 88→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
 89→    { redirect: 'manual' });
 90→  const cookies = parseCookies(res);
 91→  const allCookies = Object.entries(cookies);
 92→  if (allCookies.length > 0) {
 93→    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
 94→    console.log(`   ✅ 登录成功\n`);
 95→    return;
 96→  }
 97→  console.log('❌ 登录失败');
 98→  process.exit(1);
 99→}
