101→let savedSessions = {};
102→function saveSession(name) {
103→  savedSessions[name] = { cookie };
104→}
105→function restoreSession(name) {
106→  ({ cookie } = savedSessions[name]);
107→}
108→
109→async function loginAs(email) {
110→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
111→    { redirect: 'manual' });
112→  const cookies = parseCookies(res);
113→  const allCookies = Object.entries(cookies);
114→  if (allCookies.length > 0) {
115→    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
116→    return true;
117→  }
118→  console.log(`  ⚠️  登录 ${email} 失败，跳过`);
119→  return false;
120→}
