122→// ========== 工具函数 ==========
123→
124→/** 递归收集文件夹树中所有节点 */
125→function flattenFolders(folders) {
126→  const result = [];
127→  for (const f of (folders || [])) {
128→    result.push(f);
129→    result.push(...flattenFolders(f.children));
130→  }
131→  return result;
132→}
