138→async function test_S1_managedSpaces_basic() {
139→  console.log('\n📋 §1. GET /managedSpaces - 正常流程');
140→
141→  const res = await GET('/spaceNode/migration/managedSpaces');
142→  assert('§1 接口返回 success', res.success === true, res);
143→  assert('§1 data 是数组', Array.isArray(res.data), res.data);
144→  assert('§1 至少返回 1 个空间站', res.data?.length > 0, res.data?.length);
145→
146→  if (res.data?.length > 0) {
147→    const first = res.data[0];
148→    assert('§1 空间站含 spaceId (string)', typeof first.spaceId === 'string', first.spaceId);
149→    assert('§1 空间站含 name (string)', typeof first.name === 'string', first.name);
150→    const foldersDeployed = first.folders !== undefined;
151→    assert('§1 空间站含 folders 字段（需部署后生效）', foldersDeployed, first);
152→    if (foldersDeployed) {
153→      assert('§1 folders 是数组', Array.isArray(first.folders), first.folders);
154→    }
155→
156→    // 找一个有 folders 的空间站
157→    const withFolders = foldersDeployed ? res.data.find(s => s.folders && s.folders.length > 0) : null;
158→    if (withFolders) {
159→      const folder = withFolders.folders[0];
160→      assert('§1 folder 含 id', folder.id != null, folder);
161→      assert('§1 folder 含 name (string)', typeof folder.name === 'string', folder.name);
162→      assert('§1 folder 含 children (数组)', Array.isArray(folder.children), folder.children);
163→
164→      // 保存测试数据
165→      CONFIG.targetSpaceId = withFolders.spaceId;
166→      CONFIG.targetFolderId = folder.id;
167→      console.log(`   ℹ️  目标空间站: ${withFolders.spaceId} (${withFolders.name}), 目标文件夹ID: ${folder.id} (${folder.name})`);
168→    } else {
169→      // 没有文件夹的空间站也行，设置 targetSpaceId
170→      CONFIG.targetSpaceId = first.spaceId;
171→      console.log(`   ℹ️  目标空间站: ${first.spaceId} (${first.name})，无文件夹`);
172→    }
173→  }
174→}
