176→async function test_S1_managedSpaces_folderStructure() {
177→  console.log('\n📋 §1. managedSpaces - folders 结构深度验证');
178→
179→  const res = await GET('/spaceNode/migration/managedSpaces');
180→  if (!res.success || !res.data) return;
181→
182→  // 检查第一个空间站是否有 folders 字段（判断功能是否已部署）
183→  const first = res.data[0];
184→  if (first.folders === undefined) {
185→    console.log('   ⚠️  folders 字段不存在，功能分支尚未部署到测试环境，跳过 folders 深度验证');
186→    assert('§1 [待部署] folders 字段存在', false, 'undefined - 需要部署后重测');
187→    return;
188→  }
189→
190→  // 抽查前 3 个空间站的 folders 是数组
191→  const sample = res.data.slice(0, 3);
192→  for (const space of sample) {
193→    assert(`§1 ${space.name} folders 非null`, space.folders != null, space.folders);
194→    assert(`§1 ${space.name} folders 是数组`, Array.isArray(space.folders), typeof space.folders);
195→  }
196→
197→  // 找有嵌套文件夹的空间站验证递归结构
198→  const withFolders = res.data.find(s => s.folders && s.folders.length > 0);
199→  if (withFolders) {
200→    const allFolders = flattenFolders(withFolders.folders);
201→    console.log(`   ℹ️  ${withFolders.name} 共 ${allFolders.length} 个文件夹节点`);
202→    // 验证前 5 个节点的结构（避免大量输出）
203→    for (const f of allFolders.slice(0, 5)) {
204→      assert(`§1 文件夹 ${String(f.id)} 含 name`, typeof f.name === 'string', f);
205→      assert(`§1 文件夹 ${String(f.id)} children 是数组`, Array.isArray(f.children), f.children);
206→    }
207→  } else {
208→    console.log('   ℹ️  所有空间站均无文件夹，跳过递归结构验证');
209→  }
210→}
