package com.yottastudios.ns.collabspace.workspace.vo;

import com.fasterxml.jackson.annotation.JsonIgnore;
import com.fasterxml.jackson.annotation.JsonInclude;
import com.fasterxml.jackson.databind.annotation.JsonDeserialize;
import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.yottastudios.ns.collabspace.base.service.RelIdProvider;
import com.yottastudios.ns.collabspace.shared.support.deserializer.DateFormatToLocalDateTimeDeserializer;
import com.yottastudios.ns.collabspace.shared.support.serializer.LocalDateTimeToMilliSerializer;
import com.yottastudios.ns.collabspace.shared.support.serializer.LongToStringSerializer;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import io.swagger.v3.oas.annotations.media.Schema;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
import org.springframework.beans.BeanUtils;

import java.time.LocalDateTime;

@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "SpaceNodeVo")
public class SpaceNodeVo implements RelIdProvider {

    @Schema(description = "SpaceNode的ID")
    @JsonSerialize(using = LongToStringSerializer.class)
    private Long id;

    @Schema(description = "spaceId")
    private String spaceId;

    @Schema(description = "spaceId")
    private String appSpaceId;

    @Schema(description = "name")
    private String name;

    @Schema(description = "description")
    private String description;

    @Schema(description = "三方应用里对应的文件的ID")
    private String appSpaceNodeId;

    @Schema(description = "该节点具体的文件类型, " + SpaceNodeTypeEnum.ENUM_MAPPINGS)
    private Integer type;

    @Schema(description = "是否已收藏, true:收藏, false:未收藏")
    private Boolean isStarred;

    @Schema(description = "创建人")
    private String creatorName;

    @Schema(description = "用户在此节点的角色")
    private String role;

    @Schema(description = "Node Permissions")

