@GetResource(path = "/testLogin/{email}", requiredPermission = false, requiredLogin = false)
@Operation(summary = "测试服email登录")
public void testLogin(@PathVariable final String email, @RequestParam(required = false) String redirectUrl, HttpServletResponse response) throws IOException {
    if (!constProperties.isTestServer()) {
        throw new BusinessException(AuthException.TEST_SERVER_ONLY);
    }
    UserSimpleInfoVo userByEmail = apitableGrpcClientService.getUserByEmail(email);
    Long userId;
    if (userByEmail == null) {
        userId = authService.register(email, EmailUtil.getEmailPrefix(email),"123456", false);
    } else {
        userId = userByEmail.getId();
    }
    SessionContext.setUserId(userId);
    JwtUtil.setJwtToCookie(response, userId);
    if (redirectUrl != null) {
        response.sendRedirect(redirectUrl);
    }
}

@PostResource(path = "/jwtVerify", requiredPermission = false ,requiredLogin = false)
@Operation(summary = "Verify jwt", description = "Verify jwt and return user info")
public ResponseData<UserSimpleInfoVo> jwtVerify(@RequestBody @Valid JwtVerifyRo ro) {
    String userId = JwtUtil.getUserId(ro.getJwt());
    ExceptionUtil.isNotBlank(userId, AuthException.FORBIDDEN);
    return ResponseData.success(apitableGrpcClientService.getUserById(Long.parseLong(userId)));
}

