package com.yottastudios.ns.collabspace.workspace.enums;

import com.fasterxml.jackson.annotation.JsonValue;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import lombok.AllArgsConstructor;
import lombok.Getter;

/**
 * 迁移类型枚举
 */
@Getter
@AllArgsConstructor
public enum MigrationTypeEnum {

    INTRA_SERVER(1, "服务器内迁移"),

    CROSS_SERVER(2, "跨服务器迁移");

    @JsonValue
    private final Integer value;

    private final String description;

    public static MigrationTypeEnum fromValue(Integer value) {
        for (MigrationTypeEnum type : MigrationTypeEnum.values()) {
            if (type.getValue().equals(value)) {
                return type;
            }
        }
        throw new BusinessException(SpaceNodeException.INVALID_TYPE);
    }

    public static final String INTRA_SERVER_DESC = "服务器内迁移";
    public static final String CROSS_SERVER_DESC = "跨服务器迁移";

    public static final String ENUM_MAPPINGS =
            "1: " + INTRA_SERVER_DESC + ", " +
            "2: " + CROSS_SERVER_DESC;
}

