/**
 * 创建批量多源空间站迁移任务（无需 x-space-id header）
 * @returns batchId
 */
export const createBatchMigrationTask = (data: {
  items: { sourceSpaceId: string; spaceNodeIds: string[] }[];
  targetSpaceId: string;
  isRemained?: boolean;
}) => fetchData<typeof data, string>({
  url: '/api/v1/spaceNode/migration/createBatchMigrationTask',
  method: 'POST',
  data,
});

/** 查询批量迁移任务进度 */
export const getBatchMigrationProgress = (batchId: string) => fetchData<void, IBatchMigrationProgress>({
  url: `/api/v1/spaceNode/migration/batch/${batchId}`,
});

