        Long userId = SessionContext.getUserId();
        String sourceSpaceId = SpaceHolder.get();
        log.info("[lbl][2263-mirror-copy][Migration][CREATE] 创建迁移任务请求, userId={}, sourceSpaceId={}, targetSpaceId={}, targetParentNodeId={}, nodeIds={}",
                userId, sourceSpaceId, ro.getTargetSpaceId(), ro.getTargetParentNodeId(), ro.getSpaceNodeIds());
        if (ro.getIsRemained() == null) {
            // 默认保留
            ro.setIsRemained(true);
        }
        String taskId = spaceNodeMigrationUpdateManager.createMigrationTask(
                ro.getSpaceNodeIds(),
                ro.getTargetSpaceId(),
                sourceSpaceId,
                userId,
                ro.getIsRemained(),
                ro.getTargetParentNodeId()
        );
        return ResponseData.success(taskId);
    }

    @PostResource(path = "/createBatchMigrationTask", requiredPermission = false)
    @Operation(summary = "Create batch migration task for multiple source spaces")
