}

async function test_S2_createTask_paramValidation() {
  console.log('\n📋 §2. POST /createMigrationTask - 参数校验');

  // 缺少必填字段 spaceNodeIds
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    targetSpaceId: CONFIG.targetSpaceId,
  });
  assert('§2 缺少 spaceNodeIds 返回错误', r1.success === false, r1);
  // 注：参数校验异常返回500是全局异常处理的已知行为，此处仅验证 success=false
  if (r1.code === 500) console.log('   ⚠️  [已知] 参数校验返回500，建议后端统一返回400');

  // 空 spaceNodeIds 列表
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [],
    targetSpaceId: CONFIG.targetSpaceId,
  });
  assert('§2 空 spaceNodeIds 返回错误', r2.success === false, r2);

  // 缺少 targetSpaceId
  const r3 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [getRealNodeId()],
  });
  assert('§2 缺少 targetSpaceId 返回错误', r3.success === false, r3);

  // 空 body
  const r4 = await POST('/spaceNode/migration/createMigrationTask', {});
  assert('§2 空 body 返回错误', r4.success === false, r4);
}

async function test_S2_createTask_notExist() {
  console.log('\n📋 §2. createMigrationTask - 不存在的数据');

  // 不存在的 spaceNodeId（合法 Long）
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [1],
    targetSpaceId: CONFIG.targetSpaceId,
  });
  assert('§2 不存在 spaceNodeId 返回错误', r1.success === false, r1);
  if (r1.code === 500) console.log('   ⚠️  [已知] 不存在的spaceNodeId返回500，建议返回业务错误码');

  // 不存在的 targetSpaceId — 当前接口不校验目标空间站是否存在，任务会创建但后续执行可能失败
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [getRealNodeId()],
    targetSpaceId: 'spcNotExist000',
  });
  assert('§2 不存在 targetSpaceId 不崩溃', r2.code !== 500, r2);
  if (r2.success) console.log('   ⚠️  [注意] 不存在的targetSpaceId也能创建任务，建议后端加校验');

  // 不存在的 targetParentNodeId — 同上，不校验目标文件夹是否存在
  const r3 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [getRealNodeId()],
    targetSpaceId: CONFIG.spaceId,
    targetParentNodeId: 1,
  });
  assert('§2 不存在 targetParentNodeId 不崩溃', r3.code !== 500, r3);
  if (r3.success) console.log('   ⚠️  [注意] 不存在的targetParentNodeId也能创建任务，建议后端加校验');
}

async function test_S2_createTask_optionalTarget() {
  console.log('\n📋 §2. createMigrationTask - targetParentNodeId 可选性');
  const nodeId = getRealNodeId();
  const targetSid = CONFIG.spaceId;  // 同空间站内复制，避免权限问题

  // 不传 targetParentNodeId（向后兼容，放根目录）— 用真实节点ID
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [nodeId],
    targetSpaceId: targetSid,
  });
  assert('§2 不传 targetParentNodeId 不报参数校验错误',
    r1.code !== 400 || r1.success === true, r1);
  assert('§2 不传 targetParentNodeId 不报500', r1.code !== 500, r1.code);
  if (r1.success) {
    console.log(`   ℹ️  任务创建成功(无目标文件夹), taskId=${r1.data}`);
  }

  // 传 null
  const r2 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [nodeId],
    targetSpaceId: targetSid,
    targetParentNodeId: null,
  });
  assert('§2 targetParentNodeId=null 不报500', r2.code !== 500, r2.code);

  // 传真实的 targetParentNodeId（用源空间站的文件夹节点）
  if (CONFIG.folderNodeId) {
    const r3 = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [nodeId],
      targetSpaceId: targetSid,
      targetParentNodeId: CONFIG.folderNodeId,
    });
    assert('§2 传真实 targetParentNodeId 不报500', r3.code !== 500, r3.code);
    if (r3.success) {
      console.log(`   ℹ️  任务创建成功(指定目标文件夹=${CONFIG.folderNodeId}), taskId=${r3.data}`);
    } else {
      console.log(`   ℹ️  带 targetParentNodeId 返回: code=${r3.code}, message=${r3.message}`);
    }
  }
}

async function test_S2_createTask_injection() {
  console.log('\n📋 §2. createMigrationTask - 注入防护');

  const nodeId = getRealNodeId();
  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE xxx;",
    "<script>alert(1)</script>",
  ];
  for (const payload of injections) {
    const r = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [nodeId],
      targetSpaceId: payload,
    });
    assert(`§2 targetSpaceId注入 "${payload.slice(0, 20)}" 非500`, r.code !== 500, r.code);
  }
}

// ---------- §3. 批量选择文件和文件夹 ----------

async function test_S3_createTask_batchSelect() {
  console.log('\n📋 §3. createMigrationTask - 批量选择（多个 spaceNodeIds）');

  const batchIds = getRealNodeIds();
  const targetSid = CONFIG.spaceId;  // 同空间站内复制

