  1→/**
  2→ * 2263-复制镜像功能优化 - 接口测试脚本
  3→ * 分支: feature/batch-copy-2263
  4→ *
  5→ * 用法: node test-api.js
  6→ * 要求: Node.js 18+（原生 fetch）
  7→ *
  8→ * 覆盖接口:
  9→ *   GET  /spaceNode/migration/managedSpaces            — 返回空间站列表（含文件夹树）
 10→ *   POST /spaceNode/migration/createMigrationTask      — 创建迁移任务（含 targetParentNodeId）
 11→ *   POST /spaceNode/migration/createBatchMigrationTask — 批量多源空间站迁移（生成 batchId）
 12→ *   GET  /spaceNode/migration/batch/{batchId}          — 查询批量迁移进度
 13→ */
 14→
 15→// ========== 配置 ==========
 16→const CONFIG = {
 17→  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
 18→  adminEmail: 'test@yottastudios.com',
 19→  normalEmail: 'test2@yottastudios.com',
 20→  spaceId: 'spcQB8z3iXMF0',  // nanbei 空间站
 21→  // 运行时动态获取
 22→  folderNodeId: null,   // type=1 的文件夹节点
 23→  fileNodeId: null,     // type=2 的文件节点
 24→  targetSpaceId: null,  // 目标空间站（从 managedSpaces 动态取）
 25→  targetFolderId: null, // 目标文件夹 ID
 26→  batchNodeIds: [],     // 批量测试用的多个节点 ID
 27→  // 批量迁移测试：多个源空间站及其节点 [{spaceId, nodeIds}]
 28→  batchSources: [],
 29→};
 30→
 31→// ========== 测试框架 ==========
 32→let passed = 0;
 33→let failed = 0;
 34→let cookie = '';
 35→
 36→function assert(name, condition, detail) {
 37→  if (condition) {
 38→    console.log(`  ✅ ${name}`);
 39→    passed++;
 40→  } else {
 41→    console.log(`  ❌ ${name}`);
 42→    if (detail !== undefined)
 43→      console.log(`     实际值:`, typeof detail === 'object'
 44→        ? JSON.stringify(detail).slice(0, 300) : detail);
 45→    failed++;
 46→  }
 47→}
 48→
 49→// ========== HTTP 工具 ==========
 50→
 51→function parseCookies(res) {
 52→  const cookies = {};
 53→  const setCookieHeaders = res.headers.getSetCookie?.() || [];
 54→  for (const header of setCookieHeaders) {
 55→    const [kv] = header.split(';');
 56→    const eqIdx = kv.indexOf('=');
 57→    if (eqIdx > 0) {
 58→      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
 59→    }
 60→  }
 61→  return cookies;
 62→}
 63→
 64→async function rawFetch(method, url, body, spaceIdOverride) {
 65→  const headers = {
 66→    'content-type': 'application/json',
 67→  };
 68→  const sid = spaceIdOverride || CONFIG.spaceId;
 69→  if (sid) headers['x-space-id'] = sid;
 70→  if (cookie) headers['cookie'] = cookie;
 71→
 72→  const opts = { method, headers, redirect: 'manual' };
 73→  if (body) opts.body = JSON.stringify(body);
 74→  return fetch(url, opts);
 75→}
 76→
 77→async function GET(path) {
 78→  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
 79→  const text = await res.text();
 80→  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
 81→}
 82→
 83→async function POST(path, body) {
 84→  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
 85→  const text = await res.text();
 86→  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
 87→}
 88→
 89→// ========== 登录管理 ==========
 90→
 91→async function login() {
 92→  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
 93→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
 94→    { redirect: 'manual' });
 95→  const cookies = parseCookies(res);
 96→  const allCookies = Object.entries(cookies);
 97→  if (allCookies.length > 0) {
 98→    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
 99→    console.log(`   ✅ 登录成功\n`);
100→    return;
101→  }
102→  console.log('❌ 登录失败');
103→  process.exit(1);
104→}
105→
106→let savedSessions = {};
107→function saveSession(name) {
108→  savedSessions[name] = { cookie };
109→}
110→function restoreSession(name) {
111→  ({ cookie } = savedSessions[name]);
112→}
113→
114→async function loginAs(email) {
115→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
116→    { redirect: 'manual' });
117→  const cookies = parseCookies(res);
118→  const allCookies = Object.entries(cookies);
119→  if (allCookies.length > 0) {
120→    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
121→    return true;
122→  }
123→  console.log(`  ⚠️  登录 ${email} 失败，跳过`);
124→  return false;
125→}
126→
127→// ========== 工具函数 ==========
128→
129→/** 递归收集文件夹树中所有节点 */
130→function flattenFolders(folders) {
131→  const result = [];
132→  for (const f of (folders || [])) {
133→    result.push(f);
134→    result.push(...flattenFolders(f.children));
135→  }
136→  return result;
137→}
138→
139→/** 递归展开节点树，收集所有节点 */
140→function flattenTree(nodes) {
141→  const result = [];
142→  for (const n of (nodes || [])) {
143→    result.push(n);
144→    if (n.children) result.push(...flattenTree(n.children));
145→  }
146→  return result;
147→}
148→
149→/** 从测试环境获取真实的 spaceNodeId（文件夹和文件）
150→ *  注意：spaceTreeById 返回的是 TreeNode<SpaceNodeVo> 结构：
151→ *    node.data.id   = SpaceNode 主键（字符串，因为 Long 超出 JS Number 安全范围）
152→ *    node.data.type = 节点类型（1=文件夹, 2=文件）
153→ *    node.data.name = 节点名称
154→ */
155→async function fetchRealNodeIds() {
156→  console.log(`\n🔍 获取真实节点数据 (spaceId: ${CONFIG.spaceId}) ...`);
157→
158→  const res = await POST('/test/spaceTreeById', { id: CONFIG.spaceId });
159→  if (!res.success || !res.data) {
160→    console.log('   ❌ 无法获取真实节点数据，将使用假数据（不会产生业务日志）');
161→    return;
162→  }
163→
164→  // 展开树，提取 data 层（真正的 SpaceNodeVo）
165→  const treeNodes = flattenTree(res.data);
166→  const allNodes = treeNodes.map(n => n.data).filter(Boolean);
167→  console.log(`   ℹ️  共 ${allNodes.length} 个节点`);
168→
169→  // type=1 文件夹, type=2 文件
170→  // id 是字符串（后端 LongToStringSerializer），直接保留字符串传给 JSON body
171→  const folders = allNodes.filter(n => n.type === 1);
172→  const files = allNodes.filter(n => n.type === 2);
173→
174→  if (folders.length > 0) {
175→    CONFIG.folderNodeId = folders[0].id;  // 字符串形式的 Long
176→    console.log(`   ✅ 文件夹节点: id=${CONFIG.folderNodeId} (${folders[0].name})`);
177→  } else {
178→    console.log('   ⚠️  未找到文件夹节点');
179→  }
180→
181→  if (files.length > 0) {
182→    CONFIG.fileNodeId = files[0].id;  // 字符串形式的 Long
