  const items = CONFIG.batchSources.map(src => ({
    sourceSpaceId: src.sourceSpaceId,
    spaceNodeIds: src.spaceNodeIds,
  }));
  const targetSid = CONFIG.spaceId;  // 迁移到当前空间站

