  for (const item of items) {
    console.log(`      - ${item.sourceSpaceId}: [${item.spaceNodeIds.join(', ')}]`);
  }

  const res = await POST('/spaceNode/migration/createBatchMigrationTask', {
    items,
    targetSpaceId: targetSid,
    isRemained: true,
  });

  assert('§5 批量迁移不报500', res.code !== 500, res);
  assert('§5 批量迁移返回 success', res.success === true, res);

