    assert('§5 查询批量进度返回 success', progressRes.success === true, progressRes);

    if (progressRes.success && progressRes.data) {
      const batchData = progressRes.data;
      assert('§5 进度返回含 batchId', batchData.batchId === batchId, batchData.batchId);
      assert('§5 进度返回含 tasks 数组', Array.isArray(batchData.tasks), batchData.tasks);

      if (batchData.tasks?.length > 0) {
        console.log(`   ℹ️  子任务数: ${batchData.tasks.length}`);
        // 验证子任务结构
        const firstTask = batchData.tasks[0];
        assert('§5 子任务含 taskId', firstTask.taskId != null, firstTask);
        assert('§5 子任务含 sourceSpaceId', firstTask.sourceSpaceId != null, firstTask);
