// ---------- §4. 真实数据完整迁移流程 ----------

async function test_S4_createTask_realData() {
  console.log('\n📋 §4. createMigrationTask - 真实数据完整迁移流程');

  const nodeId = getRealNodeId();
  // 用同一个空间站做源和目标（空间站内复制），避免跨空间站权限问题
  const targetSid = CONFIG.spaceId;

  if (!hasRealData()) {
    console.log('   ⚠️  无真实节点数据，跳过完整流程测试');
    return;
  }

  // Case 1: 复制到同空间站根目录（不传 targetParentNodeId）
  console.log(`   ℹ️  复制节点 ${nodeId} → 同空间站 ${targetSid} (根目录)`);
  const r1 = await POST('/spaceNode/migration/createMigrationTask', {
    spaceNodeIds: [nodeId],
    targetSpaceId: targetSid,
    isRemained: true,
  });
  assert('§4 同空间站复制到根目录不报500', r1.code !== 500, r1);
  if (r1.success && r1.data) {
    console.log(`   ✅ 任务ID: ${r1.data}`);
    // 查询任务状态
    const taskRes = await GET(`/spaceNode/migration/task/${r1.data}`);
    assert('§4 查询任务状态成功', taskRes.success === true, taskRes);
    if (taskRes.success) {
      console.log(`   ℹ️  任务状态: ${JSON.stringify(taskRes.data).slice(0, 300)}`);
    }
  } else {
    console.log(`   ℹ️  同空间站复制返回: code=${r1.code}, message=${r1.message}`);
  }

  // Case 2: 复制到指定文件夹（传 targetParentNodeId）
  // 用源空间站内的文件夹节点作为目标
  if (CONFIG.folderNodeId) {
    console.log(`   ℹ️  复制节点 ${nodeId} → 同空间站文件夹 ${CONFIG.folderNodeId}`);
    const r2 = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [nodeId],
      targetSpaceId: targetSid,
      targetParentNodeId: CONFIG.folderNodeId,
      isRemained: true,
    });
    assert('§4 复制到指定文件夹不报500', r2.code !== 500, r2);
    if (r2.success && r2.data) {
      console.log(`   ✅ 指定文件夹任务ID: ${r2.data}`);
      const taskRes2 = await GET(`/spaceNode/migration/task/${r2.data}`);
      assert('§4 指定文件夹任务状态查询成功', taskRes2.success === true, taskRes2);
      if (taskRes2.success) {
        console.log(`   ℹ️  任务状态: ${JSON.stringify(taskRes2.data).slice(0, 300)}`);
      }
    } else {
      console.log(`   ℹ️  指定文件夹复制返回: code=${r2.code}, message=${r2.message}`);
    }
  }

  // Case 3: 跨空间站迁移（如果 managedSpaces 里有其他空间站）
  if (CONFIG.targetSpaceId && CONFIG.targetSpaceId !== CONFIG.spaceId) {
    console.log(`   ℹ️  跨空间站: ${nodeId} → ${CONFIG.targetSpaceId}`);
    const r3 = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: [nodeId],
      targetSpaceId: CONFIG.targetSpaceId,
      isRemained: true,
    });
    assert('§4 跨空间站迁移不报500', r3.code !== 500, r3);
    if (r3.success && r3.data) {
      console.log(`   ✅ 跨空间站任务ID: ${r3.data}`);
    } else {
      console.log(`   ℹ️  跨空间站迁移返回: code=${r3.code}, message=${r3.message}`);
    }
  }

  // Case 4: 批量复制多个节点
  const batchIds = getRealNodeIds();
  if (batchIds.length > 1) {
    console.log(`   ℹ️  批量复制 ${batchIds.length} 个节点 → ${targetSid}`);
    const r4 = await POST('/spaceNode/migration/createMigrationTask', {
      spaceNodeIds: batchIds,
      targetSpaceId: targetSid,
      isRemained: true,
    });
    assert('§4 批量复制不报500', r4.code !== 500, r4);
    if (r4.success) {
      console.log(`   ✅ 批量复制任务ID: ${r4.data}`);
    } else {
      console.log(`   ℹ️  批量复制返回: code=${r4.code}, message=${r4.message}`);
    }
  }
}

