toolUseResult.originalFile:
/**
 * 2263-复制镜像功能优化 - 接口测试脚本
 * 分支: feature/batch-copy-2263
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 *
 * 覆盖接口:
 *   GET  /spaceNode/migration/managedSpaces            — 返回空间站列表（含文件夹树）
 *   POST /spaceNode/migration/createMigrationTask      — 创建迁移任务（含 targetParentNodeId）
 *   POST /spaceNode/migration/createBatchMigrationTask — 批量多源空间站迁移（生成 batchId）
 *   GET  /spaceNode/migration/batch/{batchId}          — 查询批量迁移进度
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  adminEmail: 'test@yottastudios.com',
  normalEmail: 'test2@yottastudios.com',
  spaceId: 'spcQB8z3iXMF0',  // nanbei 空间站
  // 运行时动态获取
  folderNodeId: null,   // type=1 的文件夹节点
  fileNodeId: null,     // type=2 的文件节点
  targetSpaceId: null,  // 目标空间站（从 managedSpaces 动态取）
  targetFolderId: null, // 目标文件夹 ID
  batchNodeIds: [],     // 批量测试用的多个节点 ID
  // 批量迁移测试：多个源空间站及其节点 [{spaceId, nodeIds}]
  batchSources: [],
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const eqIdx = kv.indexOf('=');
    if (eqIdx > 0) {
      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
    }
  }
  return cookies;
}

async function rawFetch(method, url, body, spaceIdOverride) {
  const headers = {
    'content-type': 'application/json',
  };
  const sid = spaceIdOverride || CONFIG.spaceId;
  if (sid) headers['x-space-id'] = sid;
  if (cookie) headers['cookie'] = cookie;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  const text = await res.text();
  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  const text = await res.text();
  try { return JSON.parse(text); } catch { return { _raw: text, _status: res.status }; }
}

// ========== 登录管理 ==========

async function login() {
  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  const allCookies = Object.entries(cookies);
  if (allCookies.length > 0) {
    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
    console.log(`   ✅ 登录成功\n`);
    return;
  }
  console.log('❌ 登录失败');
  process.exit(1);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie };
}
function restoreSession(name) {
  ({ cookie } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  const allCookies = Object.entries(cookies);
  if (allCookies.length > 0) {
    cookie = allCookies.map(([k, v]) => `${k}=${v}`).join('; ');
    return true;
  }
  console.log(`  ⚠️  登录 ${email} 失败，跳过`);
  return false;
}

// ========== 工具函数 ==========

/** 递归收集文件夹树中所有节点 */
function flattenFolders(folders) {
  const result = [];
  for (const f of (folders || [])) {
    result.push(f);
    result.push(...flattenFolders(f.children));
  }
  return result;
}

/** 递归展开节点树，收集所有节点 */
function flattenTree(nodes) {
  const result = [];
  for (const n of (nodes || [])) {
    result.push(n);
    if (n.children) result.push(...flattenTree(n.children));
  }
  return result;
}

/** 从测试环境获取真实的 spaceNodeId（文件夹和文件）
 *  注意：spaceTreeById 返回的是 TreeNode<SpaceNodeVo> 结构：
 *    node.data.id   = SpaceNode 主键（字符串，因为 Long 超出 JS Number 安全范围）
 *    node.data.type = 节点类型（1=文件夹, 2=文件）
 *    node.data.name = 节点名称
 */
async function fetchRealNodeIds() {
  console.log(`\n🔍 获取真实节点数据 (spaceId: ${CONFIG.spaceId}) ...`);

  const res = await POST('/test/spaceTreeById', { id: CONFIG.spaceId });
  if (!res.success || !res.data) {
    console.log('   ❌ 无法获取真实节点数据，将使用假数据（不会产生业务日志）');
    return;
  }

  // 展开树，提取 data 层（真正的 SpaceNodeVo）
  const treeNodes = flattenTree(res.data);
  const allNodes = treeNodes.map(n => n.data).filter(Boolean);
  console.log(`   ℹ️  共 ${allNodes.length} 个节点`);

  // type=1 文件夹, type=2 文件
  // id 是字符串（后端 LongToStringSerializer），直接保留字符串传给 JSON body
  const folders = allNodes.filter(n => n.type === 1);
  const files = allNodes.filter(n => n.type === 2);

  if (folders.length > 0) {
    CONFIG.folderNodeId = folders[0].id;  // 字符串形式的 Long
    console.log(`   ✅ 文件夹节点: id=${CONFIG.folderNodeId} (${folders[0].name})`);
  } else {
    console.log('   ⚠️  未找到文件夹节点');
  }

  if (files.length > 0) {
    CONFIG.fileNodeId = files[0].id;  // 字符串形式的 Long
    console.log(`   ✅ 文件节点: id=${CONFIG.fileNodeId} (${files[0].name})`);
  } else {
    console.log('   ⚠️  未找到文件节点');
  }

  // 收集更多文件节点用于批量测试（字符串ID）
  CONFIG.batchNodeIds = files.slice(0, 3).map(f => f.id);
  if (CONFIG.batchNodeIds.length === 0 && folders.length > 0) {
    CONFIG.batchNodeIds = folders.slice(0, 3).map(f => f.id);
  }
  console.log(`   ℹ️  批量测试节点: [${CONFIG.batchNodeIds.join(', ')}]`);
}

