import java.util.List;

public interface SpaceNodeMigrationUpdateManager {

    /**
     * 创建迁移任务, 由source(collabspace-mirror)发起
     */
    String createMigrationTask(List<Long> spaceNodeIds, String targetSpaceId, String sourceSpaceId, Long userId, Boolean isRemained, Long targetParentNodeId);

    /**
     * 接收迁移任务, 跨服务器迁移由target(collabspace-private)接收, 服务器内迁移由本服务接收
     *
     */

    String acceptMigrationTask(List<TreeNode<SpaceNodeVo>> spaceNodeTree, String email, String targetSpaceId, String sourceSpaceId, List<SpaceAppRelVo> appRels, Integer migrationType, Boolean isRemained, Long targetParentNodeId);

    /**
     * 复制一份文档
     *
     * @param spaceNodeIds  文档id
     * @param userId        登录人id
     * @param sourceSpaceId 源空间站id
     * @param targetSpaceId 要复制到的空间站的id
     */
    List<CopyFileVo> copyFile(List<Long> spaceNodeIds, Long userId, String sourceSpaceId, String targetSpaceId);

    List<CopyFileVo> copyShareFile(List<Long> spaceNodeIds, Long userId, String targetSpaceId, String shareId);


    CopyVersionSnapshotVo copyVersionSnapshot(Long spaceNodeId, String snapshotName, String sourceSpaceId,
                                              String targetSpaceId, Long userId, Integer type);

    void deleteVersionSnapshot(Long id);

    void recoverVersionSnapshot(Long id);

    void deleteOverTimeSnapshot();

    VersionSnapshotVo updateVersionSnapshot(Long id, String name);
}

