    @GetResource(path = "/syncSpaceApp", requiredPermission = false)
    @Operation(summary = "刷一遍子应用空间站")
    public void syncSpaceApp() {

        List<SpaceEntity> spaces = spaceService.list();

        //刷用户
        Set<Long> userIds = spaces.stream()
                .flatMap(space -> {
                    Set<Long> ids = new HashSet<>();
                    if (space.getOwner() != null) {
                        ids.add(space.getOwner());
                    }
                    if (space.getCreatedBy() != null) {
                        ids.add(space.getCreatedBy());
                    }
                    if (space.getUpdatedBy() != null) {
                        ids.add(space.getUpdatedBy());
                    }
                    return ids.stream();
                })
                .collect(Collectors.toSet());

        for (Long userId : userIds) {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
            CreateUserResponse res = affineHttpClientService.createUser(new CreateUserRequest(user.getEmail(), user.getNickName(), "dev"), 1861372503096078339L);// 1861372503096078339测试服的test用户
            log.info("create affine user , email: {}, name: {}, response: {}", user.getEmail(), user.getNickName(), res);
        }

        //刷空间站
        for (SpaceEntity space : spaces) {
            List<SpaceAppRelEntity> spaceAppRelEntities = spaceAppRelService.listBySpaceId(space.getSpaceId());
            Set<Integer> appTypeSet = spaceAppRelEntities.stream().map(SpaceAppRelEntity::getAppType).collect(Collectors.toSet());
            if(!appTypeSet.contains(SpaceAppTypeEnum.AFFINE.getValue())) {
                String afResult = affineHttpClientService.createWorkspace(new CreateWorkspaceRequest(space.getName(),"aio"), space.getOwner());
                log.info("affine workspace {} created by user: {} , result: {}", space.getName(), space.getOwner(), afResult);
                SpaceAppRelEntity entity = SpaceAppRelEntity.builder()
                        .spaceId(space.getSpaceId())
                        .appSpaceId(afResult)
                        .appType(SpaceAppTypeEnum.AFFINE.getValue())
                        .createdAt(space.getCreatedAt())
                        .createdBy(space.getCreatedBy())
                        .build();
                spaceAppRelService.save(entity);
            }
        }

    }

