    @GetResource(path = "/ncSnapshotCompare", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "对比 propfindAll 与 DB 查询的快照结果")
    public ResponseData<Map<String, Object>> compareSnapshot(@RequestParam String spaceName) {
        String PROPFIND_BODY = """
                <?xml version="1.0" encoding="UTF-8"?>
                <d:propfind xmlns:d="DAV:" xmlns:oc="http://owncloud.org/ns">
                    <d:prop><oc:fileid/><d:resourcetype/></d:prop>
                </d:propfind>
                """;

        // 1. propfindAll（旧方式）
        Map<String, String> propfindMap = new HashMap<>();
        try {
            NextcloudPropfindMultiStatus result = nextcloudService.propfindAll(spaceName, PROPFIND_BODY);
            if (result != null && result.getResponses() != null) {
                String admin = nextcloudProperties.getUsername();
                for (NextcloudPropfindMultiStatus.ResponseItem item : result.getResponses()) {
                    if (item == null || item.getHref() == null) continue;
                    String path = nextcloudService.extractPathFromHref(item.getHref(), admin);
                    if (path == null || path.isBlank()) continue;
                    path = path.replaceAll("^/+|/+$", "");
                    String fileId = item.getProp() != null ? item.getProp().getFileId() : null;
                    if (fileId != null) {
                        propfindMap.put(fileId, path);
                    }
                }
            }
        } catch (Exception e) {
            log.error("propfindAll failed", e);
        }

        // 2. DB 查询（新方式）
        Map<String, String> dbMap = new HashMap<>();
        try {
            NextcloudStorageFileListResp resp = nextcloudStorageService.listFilesBySpace(spaceName);
            if (resp != null && resp.getFiles() != null) {
                for (NextcloudStorageFileListResp.FileItem item : resp.getFiles()) {
                    if (item.getFileId() != null && item.getPath() != null) {
                        String path = item.getPath().replaceAll("^/+|/+$", "");
                        dbMap.put(String.valueOf(item.getFileId()), path);
                    }
                }
            }
        } catch (Exception e) {
            log.error("DB query failed", e);
        }

        // 3. 对比
        // 注意：propfind 会多返回一条 space 根目录自身的条目（path=spaceName），
        // DB 查询不含根目录（只返回其下的文件和子目录），因此 onlyInPropfind 中
        // 出现一条根目录记录是正常的，不影响对账逻辑。
        Set<String> onlyInPropfind = new HashSet<>(propfindMap.keySet());
        onlyInPropfind.removeAll(dbMap.keySet());

        Set<String> onlyInDb = new HashSet<>(dbMap.keySet());
        onlyInDb.removeAll(propfindMap.keySet());

        Map<String, Object> result = new HashMap<>();
        result.put("propfindCount", propfindMap.size());
        result.put("dbCount", dbMap.size());
        result.put("onlyInPropfind", onlyInPropfind.stream().map(id -> id + " -> " + propfindMap.get(id)).toList());
        result.put("onlyInDb", onlyInDb.stream().map(id -> id + " -> " + dbMap.get(id)).toList());
        result.put("match", onlyInPropfind.isEmpty() && onlyInDb.isEmpty());
        return ResponseData.success(result);
    }

    @GetResource(path = "/ncReconcileSpace", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "手动触发单个 Space 的 Nextcloud 路径对账")
    public ResponseData<int[]> triggerNcReconcileSpace(@RequestParam String spaceId) {
        SpaceEntity space = spaceService.getBySpaceId(spaceId);
        if (space == null || space.getName() == null) {
            throw new BusinessException("space不存在");
        }
        int[] stats = nextcloudPathReconcileTask.reconcileSpace(spaceId, space.getName());
        return ResponseData.success(stats);
    }

}

