// ---------- §6. mockCrossServerMigration 模拟跨服务器迁移 ----------

async function test_S6_mockCrossServer_paramValidation() {
  console.log('\n📋 §6. POST /test/mockCrossServerMigration - 参数校验');

  // 空 body
  const r1 = await POST('/test/mockCrossServerMigration', {});
  assert('§6 空 body 返回错误', r1.success === false, r1);

  // 缺少 sourceSpaceId
  const r2 = await POST('/test/mockCrossServerMigration', {
    email: CONFIG.adminEmail,
    targetSpaceId: CONFIG.spaceId,
    spaceNodeIds: [getRealNodeId()],
  });
  assert('§6 缺少 sourceSpaceId 返回错误', r2.success === false, r2);

  // 缺少 spaceNodeIds
  const r3 = await POST('/test/mockCrossServerMigration', {
    email: CONFIG.adminEmail,
    sourceSpaceId: CONFIG.spaceId,
    targetSpaceId: CONFIG.spaceId,
  });
  assert('§6 缺少 spaceNodeIds 返回错误', r3.success === false, r3);
}

async function test_S6_mockCrossServer_realData() {
  console.log('\n📋 §6. mockCrossServerMigration - 真实数据跨服务器迁移');

  if (!hasRealData()) {
    console.log('   ⚠️  无真实节点数据，跳过');
    return;
  }

  const nodeId = getRealNodeId();

  // Case 1: 跨服务器复制到根目录
  console.log(`   ℹ️  模拟跨服务器: ${CONFIG.spaceId} → ${CONFIG.spaceId} (type=CROSS_SERVER, 根目录)`);
  const r1 = await POST('/test/mockCrossServerMigration', {
    email: CONFIG.adminEmail,
    sourceSpaceId: CONFIG.spaceId,
    targetSpaceId: CONFIG.spaceId,
    spaceNodeIds: [nodeId],
  });
  assert('§6 跨服务器复制到根目录不报500', r1.code !== 500, r1);
  if (r1.success && r1.data) {
    console.log(`   ✅ 跨服务器任务ID: ${r1.data}`);
    // 查询任务状态，验证 type=CROSS_SERVER
    const taskRes = await GET(`/spaceNode/migration/task/${r1.data}`);
    assert('§6 查询跨服务器任务成功', taskRes.success === true, taskRes);
    if (taskRes.success && taskRes.data) {
      console.log(`   ℹ️  任务状态: ${JSON.stringify(taskRes.data).slice(0, 300)}`);
      // statusDesc 存在即可，type 字段可能不在 VO 里
    }
  } else {
    console.log(`   ℹ️  跨服务器复制返回: code=${r1.code}, message=${r1.message}`);
  }

  // Case 2: 跨服务器复制到指定文件夹
  if (CONFIG.folderNodeId) {
    console.log(`   ℹ️  模拟跨服务器: 复制到文件夹 ${CONFIG.folderNodeId}`);
    const r2 = await POST('/test/mockCrossServerMigration', {
      email: CONFIG.adminEmail,
      sourceSpaceId: CONFIG.spaceId,
      targetSpaceId: CONFIG.spaceId,
      spaceNodeIds: [nodeId],
      targetParentNodeId: CONFIG.folderNodeId,
    });
    assert('§6 跨服务器复制到文件夹不报500', r2.code !== 500, r2);
    if (r2.success) {
      console.log(`   ✅ 跨服务器+指定文件夹任务ID: ${r2.data}`);
    }
  }

  // Case 3: 跨服务器批量复制
  const batchIds = getRealNodeIds();
  if (batchIds.length > 1) {
