async function test_S5_batchMigration_realData() {
  console.log('\n📋 §5. createBatchMigrationTask - 真实数据批量迁移');

  if (CONFIG.batchSources.length === 0) {
    console.log('   ⚠️  无批量迁移源数据（batchSources 为空），跳过');
    return;
  }

  // 构造 items：每个源空间站作为一个 BatchMigrationItem
  const items = CONFIG.batchSources.map(src => ({
    sourceSpaceId: src.sourceSpaceId,
    spaceNodeIds: src.spaceNodeIds,
  }));
  const targetSid = CONFIG.spaceId;  // 迁移到当前空间站

  console.log(`   ℹ️  批量迁移: ${items.length} 个源空间站 → ${targetSid}`);
  for (const item of items) {
    console.log(`      - ${item.sourceSpaceId}: [${item.spaceNodeIds.join(', ')}]`);
  }

  const res = await POST('/spaceNode/migration/createBatchMigrationTask', {
    items,
    targetSpaceId: targetSid,
    isRemained: true,
  });

  assert('§5 批量迁移不报500', res.code !== 500, res);
  assert('§5 批量迁移返回 success', res.success === true, res);

  if (res.success && res.data) {
    const batchId = res.data;
    console.log(`   ✅ 批量迁移任务创建成功, batchId=${batchId}`);

    // 查询批量迁移进度
    console.log(`\n   🔍 查询批量迁移进度 (batchId=${batchId}) ...`);
    const progressRes = await GET(`/spaceNode/migration/batch/${batchId}`);
    assert('§5 查询批量进度返回 success', progressRes.success === true, progressRes);

    if (progressRes.success && progressRes.data) {
      const batchData = progressRes.data;
      assert('§5 进度返回含 batchId', batchData.batchId === batchId, batchData.batchId);
      assert('§5 进度返回含 tasks 数组', Array.isArray(batchData.tasks), batchData.tasks);

      if (batchData.tasks?.length > 0) {
        console.log(`   ℹ️  子任务数: ${batchData.tasks.length}`);
        // 验证子任务结构
        const firstTask = batchData.tasks[0];
        assert('§5 子任务含 taskId', firstTask.taskId != null, firstTask);
        assert('§5 子任务含 sourceSpaceId', firstTask.sourceSpaceId != null, firstTask);
        assert('§5 子任务含 status', firstTask.status != null, firstTask);
        console.log(`   ℹ️  第一个子任务: ${JSON.stringify(firstTask).slice(0, 300)}`);
      } else {
        console.log('   ⚠️  tasks 数组为空');
      }
    }
  } else {
    console.log(`   ℹ️  批量迁移返回: code=${res.code}, message=${res.message}`);
  }
}

